patch:
--- sound/sound_core.c.orig	2007-09-04 23:50:42.000000000 +0200
+++ sound/sound_core.c	2007-09-05 02:03:38.000000000 +0200
@@ -166,9 +166,9 @@
 	if (r < 0)
 		goto fail;
 	else if (r < SOUND_STEP)
-		sprintf(s->name, "sound/%s", name);
+		sprintf(s->name, "%s", name);
 	else
-		sprintf(s->name, "sound/%s%d", name, r / SOUND_STEP);
+		sprintf(s->name, "%s%d", name, r / SOUND_STEP);

 	device_create(sound_class, dev, MKDEV(SOUND_MAJOR, s->unit_minor),
 		      s->name+6);
